insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:2-7-the-labour-market:match:d97837fd', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wage rate”?", "options": ["Demand for labour that comes from demand for the product it makes", "The price of labour, set by the demand for and supply of workers", "The wage where the supply of labour equals the demand for labour", "The difference in pay workers get for different jobs"]}'::jsonb, '{"answer": 1, "explain": "“Wage rate” means: The price of labour, set by the demand for and supply of workers"}'::jsonb),
('economics:2-7-the-labour-market:match:f8d98676', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Derived demand”?", "options": ["The wage where the supply of labour equals the demand for labour", "Demand for labour that comes from demand for the product it makes", "The difference in pay workers get for different jobs", "The skills, qualifications and experience a worker builds up over time"]}'::jsonb, '{"answer": 1, "explain": "“Derived demand” means: Demand for labour that comes from demand for the product it makes"}'::jsonb),
('economics:2-7-the-labour-market:match:8e86ea6e', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Equilibrium wage”?", "options": ["The difference in pay workers get for different jobs", "The wage where the supply of labour equals the demand for labour", "The skills, qualifications and experience a worker builds up over time", "Workers cannot move jobs because their skills do not transfer"]}'::jsonb, '{"answer": 1, "explain": "“Equilibrium wage” means: The wage where the supply of labour equals the demand for labour"}'::jsonb),
('economics:2-7-the-labour-market:match:23d9eb70', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wage differential”?", "options": ["The skills, qualifications and experience a worker builds up over time", "Workers cannot move jobs because their skills do not transfer", "The difference in pay workers get for different jobs", "Workers cannot or will not move to another area for work"]}'::jsonb, '{"answer": 2, "explain": "“Wage differential” means: The difference in pay workers get for different jobs"}'::jsonb),
('economics:2-7-the-labour-market:match:e0cf8934', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Human capital”?", "options": ["The skills, qualifications and experience a worker builds up over time", "Workers cannot move jobs because their skills do not transfer", "Workers cannot or will not move to another area for work", "An organisation that bargains collectively for higher pay and better conditions"]}'::jsonb, '{"answer": 0, "explain": "“Human capital” means: The skills, qualifications and experience a worker builds up over time"}'::jsonb),
('economics:2-7-the-labour-market:match:7cdd5c9e', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Occupational immobility”?", "options": ["Workers cannot or will not move to another area for work", "An organisation that bargains collectively for higher pay and better conditions", "Workers cannot move jobs because their skills do not transfer", "The lowest hourly pay an employer is legally allowed to offer"]}'::jsonb, '{"answer": 2, "explain": "“Occupational immobility” means: Workers cannot move jobs because their skills do not transfer"}'::jsonb),
('economics:2-7-the-labour-market:match:845cf5c6', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Geographical immobility”?", "options": ["An organisation that bargains collectively for higher pay and better conditions", "The lowest hourly pay an employer is legally allowed to offer", "Workers cannot or will not move to another area for work", "Total earnings before any deductions, including bonuses and overtime"]}'::jsonb, '{"answer": 2, "explain": "“Geographical immobility” means: Workers cannot or will not move to another area for work"}'::jsonb),
('economics:2-7-the-labour-market:match:2fa4be11', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade union”?", "options": ["The lowest hourly pay an employer is legally allowed to offer", "Total earnings before any deductions, including bonuses and overtime", "An organisation that bargains collectively for higher pay and better conditions", "Take-home pay after income tax, National Insurance and pension are deducted"]}'::jsonb, '{"answer": 2, "explain": "“Trade union” means: An organisation that bargains collectively for higher pay and better conditions"}'::jsonb),
('economics:2-7-the-labour-market:match:d55f341a', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National Minimum Wage”?", "options": ["Total earnings before any deductions, including bonuses and overtime", "Take-home pay after income tax, National Insurance and pension are deducted", "The market where the factors of production, like labour, are bought and sold", "The lowest hourly pay an employer is legally allowed to offer"]}'::jsonb, '{"answer": 3, "explain": "“National Minimum Wage” means: The lowest hourly pay an employer is legally allowed to offer"}'::jsonb),
('economics:2-7-the-labour-market:match:2b48b33f', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gross pay”?", "options": ["Take-home pay after income tax, National Insurance and pension are deducted", "Total earnings before any deductions, including bonuses and overtime", "The market where the factors of production, like labour, are bought and sold", "Where firms demand labour and households supply it, setting the wage rate"]}'::jsonb, '{"answer": 1, "explain": "“Gross pay” means: Total earnings before any deductions, including bonuses and overtime"}'::jsonb),
('economics:2-7-the-labour-market:match:f52a0e5c', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net pay”?", "options": ["The market where the factors of production, like labour, are bought and sold", "Where firms demand labour and households supply it, setting the wage rate", "Take-home pay after income tax, National Insurance and pension are deducted", "The price of labour, set by the demand for and supply of workers"]}'::jsonb, '{"answer": 2, "explain": "“Net pay” means: Take-home pay after income tax, National Insurance and pension are deducted"}'::jsonb),
('economics:2-7-the-labour-market:match:6fab0ff3', 'economics', 'economics:2-7-the-labour-market', '2.7 The Labour Market', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Factor market”?", "options": ["The market where the factors of production, like labour, are bought and sold", "Where firms demand labour and households supply it, setting the wage rate", "The price of labour, set by the demand for and supply of workers", "Demand for labour that comes from demand for the product it makes"]}'::jsonb, '{"answer": 0, "explain": "“Factor market” means: The market where the factors of production, like labour, are bought and sold"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:6e5b08fe', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Which one of the following is the most likely effect if interest rates rise in the UK?", "options": ["A decrease in investment", "An increase in national income", "Households will borrow more", "Households will save less"], "hint": "Higher interest rates make borrowing dearer and saving more rewarding. Which option follows from that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A decrease in investment</strong></p>\n<ul>\n<li>Higher interest rates raise the cost of borrowing, so firms invest less. The other options describe effects of a FALL in interest rates (more borrowing, less saving) or are unrelated.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:2117703c', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q4", "question": "What would an economist consider to be the best example of money?", "options": ["A cheque", "A credit card", "A fifty-pound note", "A mobile phone pay app"], "hint": "Money is what is generally accepted as a means of payment in itself — not a way of accessing or promising money held elsewhere.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — A fifty-pound note</strong></p>\n<ul>\n<li>Cash is money itself and is generally accepted as a means of payment. A cheque, credit card or pay app are only ways of transferring or accessing money held elsewhere.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Most of the candidates gave C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:80a7cd98', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q5", "question": "The Bank of England has announced a large increase in the rate of interest. What is the most likely effect on consumers?", "options": ["Additional spending", "Decreased borrowing", "Increased demand for labour", "Increased investment"], "hint": "For consumers, a higher interest rate makes loans and credit dearer. What do they do less of?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Decreased borrowing</strong></p>\n<ul>\n<li>Dearer credit means consumers borrow less. Extra spending and investment are effects of a FALL in rates; demand for labour is a decision for firms, not consumers.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:d887cc84', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A large firm wants to expand its output. It needs to borrow £100 000 for 10 years. Which financial institution is the firm most likely to go to for this loan?", "options": ["A commercial bank", "An insurance company", "The central bank", "The local building society"], "hint": "Which institution makes business loans to firms? (The central bank deals with government and other banks, not ordinary firms.)", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A commercial bank</strong></p>\n<ul>\n<li>Commercial banks make loans to businesses. Insurance companies and building societies do not typically fund business expansion, and the central bank does not lend to individual firms.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option A as the correct response. However, Option C was popular and showed a misunderstanding of the role of the central bank.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:dc361129', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Money is widely accepted as a means of buying and selling products. In this situation, money is acting as a", "options": ["factor of production", "medium of exchange", "source of income", "type of credit"], "hint": "When money is used to buy and sell goods, which function of money is that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: B — medium of exchange</strong></p>\n<ul>\n<li>Using money to buy and sell goods is its role as a medium of exchange. It is not a factor of production, and being accepted for exchange is not the same as credit or income.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:08cc953b', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q9", "question": "What is a function of the Bank of England?", "options": ["Issuing bank notes", "Making business loans", "Offering savings accounts", "Regulating the stock market"], "hint": "Which of these is a job for the central bank, rather than a commercial bank or another regulator?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — Issuing bank notes</strong></p>\n<ul>\n<li>Issuing notes is a central-bank function. Business loans and savings accounts are provided by commercial banks; regulating the stock market is done by other regulators.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:a4b15af1', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q10", "question": "The financial sector allows consumers and producers to manage imbalances between income and expenditure by", "options": ["making loans and overdrafts available", "providing savings and investments", "rationing the available liquidity", "setting suitable interest rates"], "hint": "An imbalance means spending more than income right now. Which service bridges that gap?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — making loans and overdrafts available</strong></p>\n<ul>\n<li>Loans and overdrafts let people spend when expenditure temporarily exceeds income. Savings/investments handle surpluses, not shortfalls.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:1d9869b1', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q11", "question": "A company will need to use the services of different financial institutions. Which of the following financial institutions is the company most unlikely to use?", "options": ["Building society", "Central bank", "Commercial bank", "Insurance company"], "hint": "The central bank deals with the government and other banks — not with ordinary companies.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Central bank</strong></p>\n<ul>\n<li>A company would use commercial banks, building societies and insurers, but not deal directly with the central bank, which serves the government and the banking system.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:07f02274', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q12", "question": "If interest rates rise", "options": ["consumers pay less for credit", "firms can invest more cheaply", "people will save less", "the government pays more to fund its debt"], "hint": "Higher rates make ALL borrowing dearer — including the government''s borrowing.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — the government pays more to fund its debt</strong></p>\n<ul>\n<li>Higher rates raise the cost of all borrowing, so the government pays more on its debt. The other options are effects of a FALL in interest rates.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:238ef5be', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Money is different from other assets because it", "options": ["can be stored by banks", "is convenient to carry", "is generally acceptable as a medium of exchange", "is made of durable metal"], "hint": "What makes money special is not how it is stored or carried, but that everyone will accept it in payment.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — is generally acceptable as a medium of exchange</strong></p>\n<ul>\n<li>The defining feature of money is that it is generally accepted in exchange for goods and services. Other assets are not.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:d00124dd', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Alpha Company borrows £1000 at 5% interest for a year. How much will Alpha Company have to pay back at the end of the year?", "options": ["£5", "£50", "£500", "£1050"], "hint": "Pay back the amount borrowed PLUS the interest: £1000 + 5% of £1000.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: D — £1050</strong></p>\n<ul>\n<li>Interest = 5% of £1000 = £50, so the total repaid is £1000 + £50 = £1050. (£50 is only the interest, not the total.)</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:1932f7bb', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q15", "question": "Which of the following is not a financial institution?", "options": ["A bank", "A building society", "An insurance company", "The government"], "hint": "Three of these provide financial services (lending, saving, insuring). Which one does not?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — The government</strong></p>\n<ul>\n<li>Banks, building societies and insurance companies are financial institutions. The government is not, even though it borrows and taxes.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:a59d029c', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q16", "question": "You put £100 into a bank account at the start of the year. One year later your account is worth £105. What is the interest rate you have received?", "options": ["0.5%", "5%", "10%", "15%"], "hint": "The £5 gain as a percentage of the £100 you put in.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: B — 5%</strong></p>\n<ul>\n<li>Interest earned = £5 on £100 = 5/100 = 5%.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:41183ec7', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q17", "question": "The government decides to lower the rate of interest in the economy. Which of the following groups is most likely to be made worse off by this decision?", "options": ["Borrowers", "Large firms", "Savers", "Small firms"], "hint": "A lower rate helps borrowers but reduces the reward for one group. Who earns less?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Savers</strong></p>\n<ul>\n<li>Lower interest rates mean savers earn a smaller return, so they are made worse off. Borrowers and firms generally benefit from cheaper borrowing.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:262449a0', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q20", "question": "When a society does not use money to exchange goods and services it is called", "options": ["a barter economy", "a market economy", "equilibrium", "specialisation in production"], "hint": "Swapping goods directly for other goods, without money, has a specific name.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — a barter economy</strong></p>\n<ul>\n<li>Barter is the direct exchange of goods and services without money.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:a964ed20', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q21", "question": "Traditionally, the main function of a building society is to", "options": ["help the government to fund any shortage in tax receipts", "insure properties against damage", "provide funds for individuals to purchase a house", "provide funds for industry to invest"], "hint": "The clue is in the name — building societies were set up to help people with one particular purchase.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — provide funds for individuals to purchase a house</strong></p>\n<ul>\n<li>Building societies traditionally provide mortgages to help individuals buy homes. Insuring property is for insurers; funding government or industry is not their main role.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:4d49b2cc', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q22", "question": "When is a cut in the rate of interest most likely to lead to an increase in investment?", "options": ["When consumer confidence is low", "When firms do not expect an increase in demand", "When firms know that there is a lack of available credit", "When there is an increase in exports"], "hint": "Cheaper borrowing only boosts investment if firms also expect to sell more. Which option means rising demand?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — When there is an increase in exports</strong></p>\n<ul>\n<li>Rising exports mean more demand, so cheaper borrowing is more likely to be used to invest. The other options describe conditions where firms would not want to expand.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:exam:bffe05fb', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Medium of exchange refers to anything that sets the", "options": ["cost of goods and services acceptable to all parties in a transaction", "payment of goods and services acceptable to all parties in a transaction", "price of goods and services acceptable to all parties in a transaction", "standard of value of goods and services acceptable to all parties involved in a transaction"], "hint": "A medium of exchange sets a common measure that everyone accepts — the ''standard of value''.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — the standard of value of goods and services acceptable to all parties involved in a transaction</strong></p>\n<ul>\n<li>A medium of exchange sets a standard of value accepted by all parties. This is the precise definition used in the specification.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:f72fdea4', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "Money is best defined as...", "options": ["The savings held by the Bank of England", "Anything generally accepted as a means of payment for goods and services", "Only the notes and coins issued by the Royal Mint", "Any item that can be swapped in a barter deal"]}'::jsonb, '{"answer": 1, "explain": "Money is anything generally accepted as a means of payment — notes, coins and bank deposits. It is more than just cash, and barter is what money replaces."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:54e2209a', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT money itself?", "options": ["Money in a current account", "A credit card", "A one-pound coin", "A ten-pound note"]}'::jsonb, '{"answer": 1, "explain": "A credit card just accesses money you can borrow or hold — it is not money itself. Notes, coins and bank deposits are money."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:37a16874', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "The problem with barter that money removes is the...", "options": ["Law of diminishing returns", "Diseconomy of scale", "Free-rider problem", "Double coincidence of wants"]}'::jsonb, '{"answer": 3, "explain": "Barter needs each trader to want exactly what the other offers — the double coincidence of wants. Money lets exchange happen without that match."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:06773ec8', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "Which of these is a function of the Bank of England?", "options": ["Offering current accounts to the public", "Issuing banknotes and setting the bank rate", "Providing mortgages to first-time buyers", "Selling car insurance to households"]}'::jsonb, '{"answer": 1, "explain": "The central bank issues notes and sets the bank rate. Accounts, mortgages and insurance come from commercial banks, building societies and insurers."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:79af8f29', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "A building society differs from a commercial bank mainly because it is...", "options": ["Owned by the government", "The bank that sets interest rates", "A mutual, owned by its members", "Not allowed to offer mortgages"]}'::jsonb, '{"answer": 2, "explain": "Building societies are mutuals owned by their members; commercial banks are owned by shareholders. Both can offer mortgages and savings."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:78fee4f9', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "A firm needs to borrow £100,000 for ten years. Which institution is it LEAST likely to use?", "options": ["A building society", "An investment bank", "A commercial bank", "The central bank"]}'::jsonb, '{"answer": 3, "explain": "The central bank does not lend to ordinary firms — it is the bank for banks and government. Businesses borrow from commercial or investment banks."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:07b2c282', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "If the rate of interest rises, the level of saving is most likely to...", "options": ["Fall, because saving is less rewarding", "Rise, because saving is more rewarding", "Fall, because borrowing is cheaper", "Stay exactly the same"]}'::jsonb, '{"answer": 1, "explain": "A higher rate raises the reward for saving, so saving tends to rise while borrowing and investment fall."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:7bd03db6', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "A cut in interest rates is most likely to increase...", "options": ["Saving and the reward for savers", "The amount the government pays on its debt", "The cost of business loans", "Borrowing and investment"]}'::jsonb, '{"answer": 3, "explain": "Cheaper borrowing encourages firms and households to borrow, invest and spend. The other options are effects of a RISE in rates."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:60bfeeb4', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "A firm borrows £2,000 at 5% interest for one year. How much must it repay in total?", "options": ["£2,100", "£2,500", "£100", "£2,005"]}'::jsonb, '{"answer": 0, "explain": "Interest = 5% of £2,000 = £100. Total repaid = £2,000 + £100 = £2,100. (£100 is only the interest.)"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:mcq:7a5b1cc9', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'mcq', 'mcq', 1, '{"question": "Traditionally, the main service a building society provides is...", "options": ["Loans to fund government spending", "Insurance against property damage", "Setting the country''s base interest rate", "Mortgages so individuals can buy a house"]}'::jsonb, '{"answer": 3, "explain": "Building societies traditionally provide mortgages to help members buy homes, alongside savings products."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:76d49a63', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "A cheque is an example of money."}'::jsonb, '{"answer": false, "explain": "A cheque is not money — it is just a way of accessing money held in the bank. Money is notes, coins and bank deposits."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:3d6aeaa1', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "Money removes the barter problem known as the double coincidence of wants."}'::jsonb, '{"answer": true, "explain": "Money lets people exchange goods that are not of equal value without needing a matching want on both sides."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:1f7811ec', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "The Bank of England provides loans and current accounts to ordinary businesses."}'::jsonb, '{"answer": false, "explain": "The central bank is the ''bank for banks'' and banker to government — commercial banks serve ordinary firms and households."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:5625084a', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "A building society is owned by its shareholders."}'::jsonb, '{"answer": false, "explain": "A building society is a MUTUAL, owned by its members (savers and borrowers). It is commercial banks that are owned by shareholders."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:845e2afd', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "A rise in interest rates tends to reduce borrowing and investment."}'::jsonb, '{"answer": true, "explain": "Dearer borrowing and a higher opportunity cost of spending mean firms and households borrow, invest and spend less."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:72878356', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "Insurance companies provide compensation for a specified loss in return for a premium."}'::jsonb, '{"answer": true, "explain": "Policyholders pay a regular premium; the insurer pays out if the insured event (theft, damage, death) happens."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:85610163', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "When interest rates fall, savers earn a higher return on their savings."}'::jsonb, '{"answer": false, "explain": "Lower rates mean a SMALLER reward for saving, so savers are worse off. Borrowers gain from cheaper loans."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tf:ad9a8628', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tf', 'tf', 1, '{"question": "As a medium of exchange, money sets a standard of value that all parties in a transaction accept."}'::jsonb, '{"answer": true, "explain": "That is the precise definition the exam wants — a standard of value AND acceptable to all parties."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:learn:f7b34044', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'learn', 'mcq', 1, '{"readingTitle": "Money and the medium of exchange", "reading": "<p><strong>Money is anything that is generally accepted as a means of payment for goods and services.</strong> It includes notes, coins and money held in the bank (current and savings accounts). Cheques, debit and credit cards are <strong>NOT money</strong> — they are just convenient ways of accessing money you already hold.</p>\n<h4>The problem money solves: barter</h4>\n<ul>\n<li><strong>Barter</strong> is the direct swapping of one good or service for another, without money.</li>\n<li>Its big weakness is the <strong>double coincidence of wants</strong>: for a swap to happen, each person must want exactly what the other is offering AND be willing to give up what the other wants — a hard condition to meet.</li>\n<li><strong>Money removes this problem.</strong> A farmer with a cow worth far more than some groceries can sell the cow for money, then spend just a small part of that money on the groceries — no matching want is needed on both sides.</li>\n</ul>\n<h4>Medium of exchange — learn the precise wording</h4>\n<ul>\n<li>As a <strong>medium of exchange</strong>, money is <strong>anything that sets a standard of value for goods and services that all parties in a transaction accept.</strong></li>\n<li>The examiner report is blunt: vague answers about \"using money to buy things\" miss the two attributes needed — <strong>setting the standard of value</strong> and being <strong>acceptable to all parties</strong>. Reference to avoiding barter / the double coincidence of wants also earns credit.</li>\n</ul>\n<h4>Exam scope — don''t over-answer</h4>\n<ul>\n<li>This specification only requires <strong>money as a medium of exchange</strong>. Other \"functions of money\" (store of value, unit of account, standard of deferred payment) are useful background but are <strong>not on this spec</strong> — the real mark scheme refused to credit them.</li>\n</ul>", "question": "Which is the best definition of money as a ''medium of exchange''?", "options": ["Something that sets a standard of value accepted by all parties in a transaction", "A credit card used to pay in shops", "The total savings held in a bank account", "Any notes and coins printed by the government"]}'::jsonb, '{"answer": 0, "explain": "The precise wording the exam wants: sets a standard of value AND is acceptable to all parties. Cards are not money; notes/coins are only examples."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:learn:c888d17c', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'learn', 'mcq', 1, '{"readingTitle": "The financial sector and its institutions", "reading": "<p>The <strong>financial sector</strong> is made up of financial organisations and their products. The four you must know are the <strong>Bank of England, commercial banks, building societies and insurance companies</strong>.</p>\n<h4>The Bank of England (the central bank)</h4>\n<ul>\n<li><strong>Issues banknotes</strong> in England and Wales (coins are made by the Royal Mint) and keeps currency secure, e.g. polymer notes.</li>\n<li><strong>Sets the bank rate</strong> (base interest rate) as part of monetary policy — this influences the rates people pay on loans and earn on savings.</li>\n<li><strong>Provides stability</strong> through regulation (tightened after the 2008 financial crisis) and acts as the <strong>\"bank for banks\"</strong> and banker to the government (managing government bonds and foreign reserves).</li>\n<li>Crucially, it does <strong>NOT</strong> run accounts for ordinary people or lend to individual firms.</li>\n</ul>\n<h4>Commercial banks</h4>\n<ul>\n<li>Accept <strong>deposits</strong> (paying interest a little below the bank rate) and keep money safe.</li>\n<li>Make <strong>payments</strong> for customers (cards, cheques, direct debits, phone apps).</li>\n<li>Provide <strong>loans</strong> (interest above the bank rate) and <strong>overdrafts</strong>, plus services like safe deposit boxes.</li>\n</ul>\n<h4>Building societies</h4>\n<ul>\n<li><strong>Mutual institutions</strong> — owned by their members (savers and borrowers), not by shareholders, and run for members'' benefit.</li>\n<li>Specialise in <strong>savings</strong> and <strong>mortgages</strong> — traditionally, providing funds for individuals to buy a house.</li>\n</ul>\n<h4>Insurance companies</h4>\n<ul>\n<li>Provide <strong>compensation</strong> if a specified event happens (car, home, life insurance) in return for a regular payment called a <strong>premium</strong>.</li>\n<li><strong>Life insurance</strong> pays a sum to the family to replace lost income when the policyholder dies.</li>\n</ul>", "question": "What makes a building society different from a commercial bank?", "options": ["It is the only institution that offers loans", "It is owned and run by the government", "It is a mutual, owned by its members rather than shareholders", "It sets the country''s base interest rate"]}'::jsonb, '{"answer": 2, "explain": "Building societies are mutuals owned by their members; commercial banks are owned by shareholders. Setting the base rate is the Bank of England''s job."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:learn:eba85ca9', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'learn', 'mcq', 1, '{"readingTitle": "What the financial sector does — and why it matters", "reading": "<p>The financial sector''s core job is to <strong>channel funds from savers to borrowers</strong>, so households, firms and government can spend and invest even when they do not hold the cash themselves. Boiled down, it provides three things:</p>\n<ul>\n<li><strong>Credit</strong> — the ability to borrow money you do not currently have.</li>\n<li><strong>Liquidity</strong> — the ability to turn assets into cash.</li>\n<li><strong>Risk management</strong> — tools such as insurance to handle different risks.</li>\n</ul>\n<h4>Importance for consumers</h4>\n<ul>\n<li>Cards and apps let people pay without cash; credit lets them buy expensive items now and pay later; overdrafts bridge gaps between income and spending; savings help them afford costly goods; insurance protects against loss.</li>\n</ul>\n<h4>Importance for producers</h4>\n<ul>\n<li>Loans fund investment and expansion; overdrafts smooth cash flow when income dips; insurance covers property and risky projects; banks keep takings safe and pay interest on savings.</li>\n</ul>\n<h4>Importance for government</h4>\n<ul>\n<li>The financial sector is <strong>almost always important</strong> to government, so questions usually ask about the effect of a specific action on a <strong>macro target</strong> (economic growth, low inflation, low unemployment) rather than \"is it important?\".</li>\n</ul>\n<h4>The golden rule: context decides importance</h4>\n<ul>\n<li>The same service is not equally important to everyone. A cash-only market stall barely needs customer credit, but a car maker''s customers rely on it. <strong>Always match the service to the specific business or consumer</strong> — that is where the application marks are won.</li>\n</ul>", "question": "In an evaluate question, what earns the application (AO2) marks about the financial sector?", "options": ["Stating that the financial sector is always important", "Defining what a bank is", "Listing every service the financial sector provides", "Matching a specific service to the particular business or consumer in the case"]}'::jsonb, '{"answer": 3, "explain": "Importance depends on context — a cash-only trader barely needs customer credit, while a car maker''s buyers rely on it. Match the service to the case."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:learn:1f88c9f8', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'learn', 'mcq', 1, '{"readingTitle": "Interest rates: saving, borrowing and investment", "reading": "<p>An <strong>interest rate</strong> is both the <strong>cost of borrowing</strong> money and the <strong>reward for saving</strong> it. The Bank of England sets the <strong>bank rate</strong>, which influences the rates across the whole economy.</p>\n<h4>When interest rates RISE</h4>\n<ul>\n<li><strong>Saving rises</strong> — the reward for saving is higher.</li>\n<li><strong>Borrowing falls</strong> — loans and credit cost more.</li>\n<li><strong>Investment falls</strong> — borrowing to invest is dearer, and a project must now earn a higher return to be worthwhile; the opportunity cost of spending rather than saving also rises.</li>\n<li>Mortgage-holders have less to spend, <strong>savers are better off</strong>, and the government pays more to fund its debt.</li>\n</ul>\n<h4>When interest rates FALL</h4>\n<ul>\n<li><strong>Saving falls, borrowing rises, investment rises.</strong> A chain: the Bank of England cuts the rate → borrowing is cheaper → firms invest and expand → they hire more workers → those workers spend more, raising demand.</li>\n<li>But it may not work if firms lack confidence or expect no rise in demand — a cut only boosts investment when firms also expect to sell more.</li>\n</ul>\n<h4>The calculations — get these exactly right</h4>\n<ul>\n<li><strong>Interest = rate × amount.</strong> 5% of a £2,000 loan for a year = 0.05 × £2,000 = £100.</li>\n<li><strong>A percentage means ÷ 100.</strong> 0.2% of £6,000 = 0.002 × £6,000 = £12 (NOT £1,200).</li>\n<li><strong>Monthly interest = yearly ÷ 12.</strong> £30,000 a year ÷ 12 = £2,500 a month.</li>\n<li><strong>Total repaid = amount borrowed + interest.</strong> £1,000 + £50 = £1,050.</li>\n<li>Always <strong>include the £ sign</strong> and <strong>show your working</strong> so the Own Figure Rule can rescue a slip.</li>\n</ul>", "question": "The Bank of England raises the bank rate. What is the most likely effect?", "options": ["Saving rises, while borrowing and investment fall", "Saving falls, while borrowing and investment rise", "Saving, borrowing and investment all rise", "Nothing changes for households or firms"]}'::jsonb, '{"answer": 0, "explain": "Higher rates reward saving and make borrowing dearer, so saving rises while borrowing and investment fall. A CUT would do the opposite."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:misc:50faa26b', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"A credit card or a cheque is money, and money is just notes and coins.\"</p><p><strong>✅ The correct idea:</strong> Money is anything GENERALLY ACCEPTED AS A MEANS OF PAYMENT for goods and services — that includes notes, coins AND money in bank accounts. Cheques, debit cards and credit cards are NOT money: they are just convenient ways of accessing money you already hold or can borrow. On the real paper, the ''best example of money'' was a fifty-pound note, not a cheque, a credit card or a pay app. So money is broader than cash (bank deposits count) but narrower than ''anything you can pay with'' (cards and cheques don''t count).</p>", "question": "Which is the best example of money?", "options": ["A mobile phone pay app", "A fifty-pound note", "A credit card", "A cheque"]}'::jsonb, '{"answer": 1, "explain": "Cash is money itself. A cheque, card or app only transfers or accesses money held elsewhere, so none of them is money."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:misc:b3ba3dc9', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"''Medium of exchange'' just means you use money to buy things.\"</p><p><strong>✅ The correct idea:</strong> That vague answer scores poorly. The mark scheme wants the precise definition: a medium of exchange sets a STANDARD OF VALUE (1) that is ACCEPTABLE TO ALL PARTIES (1) in a transaction. The examiner report said many candidates described the uses of money without naming these two attributes. Credit is also given for recognising that money avoids barter or the double coincidence of wants. Learn the two components — ''standard of value'' and ''accepted by all parties'' — not a loose ''used to buy things''.</p>", "question": "For full marks, ''money as a medium of exchange'' must be defined as something that sets a...", "options": ["Value that changes with every purchase", "Cost that only the seller has to accept", "Price that the government fixes for goods", "Standard of value accepted by all parties in a transaction"]}'::jsonb, '{"answer": 3, "explain": "The two attributes examiners want: sets a standard of value, and is acceptable to ALL parties. ''Used to buy things'' alone is not enough."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:misc:1ccd2d4f', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The Bank of England and commercial banks do basically the same job.\"</p><p><strong>✅ The correct idea:</strong> They are very different. The Bank of England is the CENTRAL bank: it issues banknotes, sets the bank rate, regulates the system and acts as the bank for other banks and the government. It does NOT run accounts for the public or lend to individual firms. So a company needing a £100,000 loan goes to a COMMERCIAL bank — it is the institution a firm is MOST UNLIKELY to use out of a list containing a bank, a building society, an insurer and the central bank. On the real paper, choosing the central bank for a business loan was the popular wrong answer.</p>", "question": "A company will use several financial institutions. Which is it most UNLIKELY to use?", "options": ["A commercial bank", "An insurance company", "A building society", "The central bank"]}'::jsonb, '{"answer": 3, "explain": "The central bank serves banks and government, not ordinary firms. Companies use commercial banks, building societies and insurers."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:misc:3d6c94ec', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"An overdraft is a good way to buy new equipment and expand the business.\"</p><p><strong>✅ The correct idea:</strong> No — that is what a LOAN is for. An overdraft is a short-term cash-flow tool: it lets a business keep paying its costs (stock, rent, insurance) when income is temporarily low, then be repaid when money comes in. On Tom''s baked-potato question the examiner report said most candidates wrongly used the overdraft to ''buy equipment and expand and pay it back later'', which is not its function. And the answer must be in context — for Tom, whose demand varies a lot, an overdraft covers the quiet days.</p>", "question": "Why is an overdraft useful for a trader like Tom, whose demand varies?", "options": ["It funds buying a bigger van to expand", "It covers costs on quiet days when income is temporarily low", "It pays a guaranteed return like a savings account", "It replaces the need to ever take a loan"]}'::jsonb, '{"answer": 1, "explain": "An overdraft is a cash-flow lifeline for the quiet days, not a way to fund expansion — that is a loan''s job."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:misc:03422293', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"0.2% of £6,000 is £1,200, so moving savings gains over a thousand pounds.\"</p><p><strong>✅ The correct idea:</strong> This is the single biggest calculation error on the topic. A percentage means DIVIDE BY 100: 0.2% = 0.002, so 0.2% of £6,000 = £12, not £1,200. Forgetting the ÷100 turned the real answer of £11.40 into a wildly wrong £1,140. Use estimation to check: 1% of £6,000 is £60, so 0.2% must be much SMALLER than that — around £12. If your working ever gives £1,200 from a sub-1% rate, you have dropped the percentage sign.</p>", "question": "What is 0.2% of £6,000?", "options": ["£60", "£1,200", "£12", "£120"]}'::jsonb, '{"answer": 2, "explain": "0.2% = 0.002, and 0.002 × £6,000 = £12. Dropping the ÷100 is what produces the wrong £1,200."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tips:36286de9', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tips', 'mcq', 1, '{"readingTitle": "definition — Definitions: give the precise wording for money and exchange", "reading": "<p>The short definition questions on this topic are easy marks IF you use the exact phrasing the mark scheme rewards — and a graveyard if you are vague.</p>\n<ul>\n<li><strong>Money</strong> = \"anything generally accepted as a means of PAYMENT for goods and services\". Answers about an \"exchange\" rather than a payment, or that just list currency examples, were not credited.</li>\n<li><strong>Medium of exchange</strong> = \"something that sets a STANDARD OF VALUE (1) acceptable to ALL PARTIES (1) in a transaction\". Naming both attributes gets 2 marks; a loose \"used to buy things\" gets 0.</li>\n<li>Mentioning that money removes <strong>barter</strong> / the <strong>double coincidence of wants</strong> also earns credit.</li>\n</ul>", "question": "For ''state what is meant by money'', which answer earns the marks?", "options": ["Something you exchange for other goods", "Any coins and banknotes you can hold", "Anything generally accepted as a means of payment for goods and services", "A card used to pay in shops"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme wants ''generally accepted means of payment''. Currency examples, ''exchange'' wording, or cards were not credited."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tips:fb5dc9d2', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Interest calculations: ÷100, ÷12, and the £ sign", "reading": "<p>Every interest sum on this topic uses the same simple rules — the marks are lost on carelessness, not difficulty:</p>\n<ul>\n<li><strong>Interest = rate × amount.</strong> 6% of a £2 million loan = £120,000; the increase from 5% to 6% is £120,000 − £100,000 = £20,000.</li>\n<li><strong>A percentage means ÷ 100.</strong> 0.2% of £6,000 = £12, not £1,200 — the most common slip on the paper.</li>\n<li><strong>Monthly = yearly ÷ 12.</strong> £500,000 at 7.5% = £37,500 a year ÷ 12 = £3,125 a month; at 6% it is £30,000 ÷ 12 = £2,500.</li>\n<li><strong>Total repaid = amount + interest</strong> (£1,000 + £50 = £1,050).</li>\n<li>Always <strong>include the £ sign</strong> (a bare number is capped) and <strong>show your working</strong> so the Own Figure Rule can save a slip.</li>\n</ul>", "question": "A £500,000 loan is charged 6% a year. What is the monthly interest?", "options": ["£30,000", "£5,000", "£250", "£2,500"]}'::jsonb, '{"answer": 3, "explain": "6% of £500,000 = £30,000 a year; ÷ 12 = £2,500 a month. Giving the yearly £30,000 or omitting the £ sign loses a mark."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tips:ca291f2f', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tips', 'mcq', 1, '{"readingTitle": "analysis — Analyse: build the interest-rate chain of reasoning", "reading": "<p>Interest-rate 6-markers want a developed CHAIN, not a list. Pick a direction and follow it right through, using the figures in the case.</p>\n<ul>\n<li><strong>Rate rises</strong> → borrowing is dearer → a project must earn a higher return to be worth it → fewer investments go ahead. Also: the opportunity cost of spending rather than saving rises, so saving is more attractive.</li>\n<li><strong>Rate falls</strong> → borrowing is cheaper → firms invest and expand → hire more workers → those workers spend more → demand rises (a multiplier).</li>\n<li><strong>Weigh a limit</strong>: a small cut may not be enough, or firms lacking confidence / expecting no rise in demand may not invest at all.</li>\n</ul>\n<p>Use the context — \"the fall from 6% to 5% lets Letusprovide borrow its £10,000 more cheaply\" beats a generic \"borrowing is cheaper\".</p>", "question": "Why might a cut in interest rates FAIL to raise a firm''s investment?", "options": ["Savers always start spending less", "Borrowing automatically becomes more expensive", "The Bank of England blocks new loans", "Firms may lack confidence or expect no rise in demand"]}'::jsonb, '{"answer": 3, "explain": "Cheaper borrowing only boosts investment if firms also expect to sell more. Low confidence or flat expected demand can stop it working."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:tips:47c03d04', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate the ''importance of the financial sector'': answer in context", "reading": "<p>The big Evaluates ask about the importance of the financial sector for a named group — and the marks turn on context and a genuine judgement.</p>\n<ul>\n<li><strong>Answer for the stated stakeholder.</strong> \"For The Music Shop''s CONSUMERS\" is about card/credit access and saving for pricey instruments — NOT about the shop itself. Answers aimed at the wrong group scored 0.</li>\n<li><strong>Match services to the case and weigh their importance.</strong> For Tom, insurance is vital (he cannot work without his insured van) but customer credit is unimportant because he deals in cash.</li>\n<li><strong>Weigh a downside</strong>: credit brings debt, cards bring fraud risk, and importance depends on age, income and attitude to risk.</li>\n<li><strong>Meet the \"importance of\" frame</strong> with a supported judgement: \"Overall it is very important, mainly for insurance and cash flow, but less so for lending to his cash-paying customers.\"</li>\n</ul>", "question": "A question asks about the financial sector''s importance for The Music Shop''s CONSUMERS. A strong answer focuses on...", "options": ["The wages the shop pays its staff", "How the shop repays its £500,000 loan", "How cards, credit and saving help consumers buy the goods", "The owners'' profit margins"]}'::jsonb, '{"answer": 2, "explain": "It is about the consumers, not the shop or its owners. Answers aimed at the wrong stakeholder scored no marks in the real report."}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:fib:e7e74cae', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'fib', 'fib', 2, '{"question": "Money is anything generally accepted as a means of ___B1___ for goods and services; a credit card is not money because it only ___B2___ money held elsewhere.", "blankOptions": {"B1": ["payment", "2100", "mortgage", "fall"], "B2": ["accesses", "premium", "fall", "banknotes"]}}'::jsonb, '{"blanks": {"B1": "payment", "B2": "accesses"}}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:fib:84a3ce24', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'fib', 'fib', 2, '{"question": "Barter suffers from the double ___B1___ of wants, which money removes by acting as a ___B2___ of exchange.", "blankOptions": {"B1": ["bank", "2100", "coincidence", "rise"], "B2": ["medium", "premium", "2100", "rise"]}}'::jsonb, '{"blanks": {"B1": "coincidence", "B2": "medium"}}'::jsonb),
