('economics:2-8-the-role-of-money-and-financial-markets:fib:6a5ba082', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'fib', 'fib', 2, '{"question": "When interest rates ___B1___, saving becomes more rewarding and borrowing tends to ___B2___.", "blankOptions": {"B1": ["bank", "100", "payment", "rise"], "B2": ["saving", "banknotes", "fall", "100"]}}'::jsonb, '{"blanks": {"B1": "rise", "B2": "fall"}}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:fib:64a8a664', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'fib', 'fib', 2, '{"question": "Interest of 5% on a £2,000 loan for one year is £___B1___, so the total repaid is £___B2___.", "blankOptions": {"B1": ["100", "premium", "banknotes", "medium"], "B2": ["mortgage", "2100", "saving", "banknotes"]}}'::jsonb, '{"blanks": {"B1": "100", "B2": "2100"}}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:49d66d95', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Money”?", "options": ["Something that sets a standard of value accepted by all parties in a transaction", "Anything generally accepted as a means of payment for goods and services", "The direct exchange of goods and services without using money", "Both traders must want exactly what the other is offering"]}'::jsonb, '{"answer": 1, "explain": "“Money” means: Anything generally accepted as a means of payment for goods and services"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:a16d7157', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Medium of exchange”?", "options": ["The direct exchange of goods and services without using money", "Both traders must want exactly what the other is offering", "Something that sets a standard of value accepted by all parties in a transaction", "The institutions and products that move money from savers to borrowers"]}'::jsonb, '{"answer": 2, "explain": "“Medium of exchange” means: Something that sets a standard of value accepted by all parties in a transaction"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:7120f142', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Barter”?", "options": ["Both traders must want exactly what the other is offering", "The direct exchange of goods and services without using money", "The institutions and products that move money from savers to borrowers", "The UK central bank — issues notes and sets the bank rate"]}'::jsonb, '{"answer": 1, "explain": "“Barter” means: The direct exchange of goods and services without using money"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:e17f318c', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Double coincidence of wants”?", "options": ["The institutions and products that move money from savers to borrowers", "The UK central bank — issues notes and sets the bank rate", "Both traders must want exactly what the other is offering", "Takes deposits and makes loans and overdrafts to households and firms"]}'::jsonb, '{"answer": 2, "explain": "“Double coincidence of wants” means: Both traders must want exactly what the other is offering"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:b09f8973', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Financial sector”?", "options": ["The UK central bank — issues notes and sets the bank rate", "Takes deposits and makes loans and overdrafts to households and firms", "The institutions and products that move money from savers to borrowers", "A mutual owned by its members, providing savings and mortgages"]}'::jsonb, '{"answer": 2, "explain": "“Financial sector” means: The institutions and products that move money from savers to borrowers"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:6076cc1d', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bank of England”?", "options": ["Takes deposits and makes loans and overdrafts to households and firms", "A mutual owned by its members, providing savings and mortgages", "Provides compensation for a specified loss in return for a premium", "The UK central bank — issues notes and sets the bank rate"]}'::jsonb, '{"answer": 3, "explain": "“Bank of England” means: The UK central bank — issues notes and sets the bank rate"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:316d503d', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Commercial bank”?", "options": ["A mutual owned by its members, providing savings and mortgages", "Takes deposits and makes loans and overdrafts to households and firms", "Provides compensation for a specified loss in return for a premium", "The cost of borrowing money and the reward for saving it"]}'::jsonb, '{"answer": 1, "explain": "“Commercial bank” means: Takes deposits and makes loans and overdrafts to households and firms"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:8f926488', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Building society”?", "options": ["Provides compensation for a specified loss in return for a premium", "The cost of borrowing money and the reward for saving it", "The base interest rate set by the Bank of England", "A mutual owned by its members, providing savings and mortgages"]}'::jsonb, '{"answer": 3, "explain": "“Building society” means: A mutual owned by its members, providing savings and mortgages"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:af2c5487', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Insurance company”?", "options": ["Provides compensation for a specified loss in return for a premium", "The cost of borrowing money and the reward for saving it", "The base interest rate set by the Bank of England", "An agreed facility to withdraw more than the account balance"]}'::jsonb, '{"answer": 0, "explain": "“Insurance company” means: Provides compensation for a specified loss in return for a premium"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:6006f248', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Interest rate”?", "options": ["The base interest rate set by the Bank of England", "An agreed facility to withdraw more than the account balance", "The regular payment made in return for insurance cover", "The cost of borrowing money and the reward for saving it"]}'::jsonb, '{"answer": 3, "explain": "“Interest rate” means: The cost of borrowing money and the reward for saving it"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:e2e903a9', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bank rate”?", "options": ["An agreed facility to withdraw more than the account balance", "The base interest rate set by the Bank of England", "The regular payment made in return for insurance cover", "Anything generally accepted as a means of payment for goods and services"]}'::jsonb, '{"answer": 1, "explain": "“Bank rate” means: The base interest rate set by the Bank of England"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:596b1ad1', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Overdraft”?", "options": ["The regular payment made in return for insurance cover", "Anything generally accepted as a means of payment for goods and services", "An agreed facility to withdraw more than the account balance", "Something that sets a standard of value accepted by all parties in a transaction"]}'::jsonb, '{"answer": 2, "explain": "“Overdraft” means: An agreed facility to withdraw more than the account balance"}'::jsonb),
('economics:2-8-the-role-of-money-and-financial-markets:match:dc74c525', 'economics', 'economics:2-8-the-role-of-money-and-financial-markets', '2.8 The Role of Money and Financial Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Premium”?", "options": ["The regular payment made in return for insurance cover", "Anything generally accepted as a means of payment for goods and services", "Something that sets a standard of value accepted by all parties in a transaction", "The direct exchange of goods and services without using money"]}'::jsonb, '{"answer": 0, "explain": "“Premium” means: The regular payment made in return for insurance cover"}'::jsonb),
('economics:3-1-economic-growth:exam:c5638b17', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q1", "question": "When national output is falling", "options": ["economic growth is negative", "economic growth is strong", "prices tend to increase rapidly", "unemployment falls as well"], "hint": "Economic growth IS the change in national output. If output is falling, what sign does growth have?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — economic growth is negative</strong></p>\n<ul>\n<li>Growth measures the change in national output, so falling output means growth is negative. Falling output would tend to RAISE unemployment, not lower it.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:02d65550', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Policy makers and producers often decide about investments on the basis of GDP data. Which one of the following statements is correct?", "options": ["Country A has the lowest output per capita", "Country A has the same output per capita as country B", "Country B has the highest output per capita", "Country C has five times more output per capita than country A"], "caseStudy": "<table style=\"width:100%;max-width:460px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\"></th><th style=\"padding:6px;\">Country A</th><th style=\"padding:6px;\">Country B</th><th style=\"padding:6px;\">Country C</th></tr>\n<tr><td style=\"padding:6px;\">GDP (£)</td><td style=\"padding:6px;\">1000</td><td style=\"padding:6px;\">2000</td><td style=\"padding:6px;\">5000</td></tr>\n<tr><td style=\"padding:6px;\">Number of inhabitants</td><td style=\"padding:6px;\">100</td><td style=\"padding:6px;\">100</td><td style=\"padding:6px;\">1000</td></tr>\n</table>", "hint": "Output per capita = GDP ÷ inhabitants. Work out all three before choosing.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: C — Country B has the highest output per capita</strong></p>\n<ul>\n<li>A = 1000 ÷ 100 = £10; B = 2000 ÷ 100 = £20; C = 5000 ÷ 1000 = £5. So B is highest and C — not A — is lowest.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:64680873', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q4", "question": "The table shows the growth in GDP for a country from 2021 to 2024. Which statement is correct?", "options": ["The country was in a recession in 2024", "The level of employment is likely to have fallen in 2022", "The level of GDP was at its highest in 2021", "The level of output fell between 2023 and 2024"], "caseStudy": "<table style=\"width:100%;max-width:360px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\"></th><th style=\"padding:6px;\">Annual growth in GDP</th></tr>\n<tr><td style=\"padding:6px;\">2021</td><td style=\"padding:6px;\">2.7%</td></tr>\n<tr><td style=\"padding:6px;\">2022</td><td style=\"padding:6px;\">–1.4%</td></tr>\n<tr><td style=\"padding:6px;\">2023</td><td style=\"padding:6px;\">2.3%</td></tr>\n<tr><td style=\"padding:6px;\">2024</td><td style=\"padding:6px;\">1.8%</td></tr>\n</table>", "hint": "Only 2022 has NEGATIVE growth — that is the year output actually fell. A smaller positive figure (2024) still means GDP is RISING.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — The level of employment is likely to have fallen in 2022</strong></p>\n<ul>\n<li>2022 is the only year with negative growth (–1.4%), so output fell and firms would need fewer workers. GDP is still growing in 2023 and 2024 (positive figures), so output did not fall between 2023 and 2024, and GDP is at its HIGHEST in 2024, not 2021.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (B).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:ee3b3a6d', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q5", "question": "How will this affect the sustainability of these households?", "options": ["A — Economic: Decrease · Social: Decrease · Environmental: Increase", "B — Economic: Decrease · Social: Increase · Environmental: Increase", "C — Economic: Decrease · Social: Increase · Environmental: Decrease", "D — Economic: Increase · Social: Decrease · Environmental: Increase"], "caseStudy": "<p>A country is seeking economic growth by investing in renewable wind energy. This has led to an increase in energy prices and more noise for households living close to the wind farms.</p>\n<table style=\"width:100%;max-width:520px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\"></th><th style=\"padding:6px;\">Economic sustainability</th><th style=\"padding:6px;\">Social sustainability</th><th style=\"padding:6px;\">Environmental sustainability</th></tr>\n<tr><td style=\"padding:6px;\">A</td><td style=\"padding:6px;\">Decrease</td><td style=\"padding:6px;\">Decrease</td><td style=\"padding:6px;\">Increase</td></tr>\n<tr><td style=\"padding:6px;\">B</td><td style=\"padding:6px;\">Decrease</td><td style=\"padding:6px;\">Increase</td><td style=\"padding:6px;\">Increase</td></tr>\n<tr><td style=\"padding:6px;\">C</td><td style=\"padding:6px;\">Decrease</td><td style=\"padding:6px;\">Increase</td><td style=\"padding:6px;\">Decrease</td></tr>\n<tr><td style=\"padding:6px;\">D</td><td style=\"padding:6px;\">Increase</td><td style=\"padding:6px;\">Decrease</td><td style=\"padding:6px;\">Increase</td></tr>\n</table>", "hint": "Take each in turn for the HOUSEHOLDS: higher energy prices (economic?), more noise (social?), wind rather than fossil fuel (environmental?).", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Decrease, Decrease, Increase</strong></p>\n<ul>\n<li>Higher energy prices leave households worse off financially → economic sustainability DECREASES. More noise harms their quality of life → social sustainability DECREASES. Renewable wind replaces polluting fossil fuels → environmental sustainability INCREASES.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (A).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:0a05045b', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Which of these is likely to cause a decrease in economic growth?", "options": ["A decrease in unemployment", "An increase in infrastructure investment", "Fewer workers coming from the EU", "More government spending on training"], "hint": "Three of these ADD to the economy''s capacity to produce. Which one shrinks the workforce?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Fewer workers coming from the EU</strong></p>\n<ul>\n<li>A smaller workforce reduces the economy''s productive capacity, lowering growth. Lower unemployment, infrastructure investment and training all tend to RAISE growth.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered C correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:38f38fda', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which statement about GDP per capita is NOT correct?", "options": ["It calculates the output per head of a country''s population", "It can be used to measure the standard of living between countries", "It represents the average income of each person in a country", "It shows a country is in recession if GDP per capita decreases"], "hint": "Read the emboldened NOT carefully. A recession is defined by falling total GDP — could GDP per capita fall while total GDP still rises?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — It shows a country is in recession if GDP per capita decreases</strong></p>\n<ul>\n<li>A recession is measured by falling total real GDP, not GDP per capita. GDP per capita can fall while total GDP still grows, if the population grows faster. The other three statements are all correct.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A common misconception was option C, due to not reading the emboldened instruction in the question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:b5228017', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Spain''s economy grew by 4.5% in 2021. A cost of this economic growth could be", "options": ["a decrease in Spain''s rate of inflation", "a decrease in unemployment in Spain", "an increase in jobs across Spain requiring repetitive work", "an increase in the number of UK tourists visiting Spain"], "hint": "The question wants a COST, not a benefit. Three options are good things. Which one is a downside for people?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — an increase in jobs across Spain requiring repetitive work</strong></p>\n<ul>\n<li>Growth through mass production can create dull, repetitive jobs — a genuine cost. Lower inflation, lower unemployment and more tourists are all benefits.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered C.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:707d6f9a', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Economic growth is measured by", "options": ["Change in GDP ÷ Change in population", "(Change in GDP ÷ Previous GDP) × 100", "New GDP − Previous GDP", "(Total GDP ÷ Previous GDP) × 100"], "hint": "Growth is expressed as a PERCENTAGE change. Which formula compares the change against the starting value and multiplies by 100?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: B — (Change in GDP ÷ Previous GDP) × 100</strong></p>\n<ul>\n<li>Growth is a percentage change: the change in GDP as a proportion of the previous GDP, × 100. Option C gives only the absolute change (not a %), and D would give an index over 100 rather than the growth rate.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:96f312e3', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q12", "question": "Which of the following is usually seen as a benefit of economic growth?", "options": ["People migrate towards the large cities", "Pollution levels are stabilised", "The government receives greater tax revenues", "The price level is likely to rise"], "hint": "Which option is clearly a GOOD outcome? Growth raises incomes and profits — what happens to what the government collects?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — The government receives greater tax revenues</strong></p>\n<ul>\n<li>Growth raises incomes and profits, so tax revenue rises — a clear benefit. Rising prices and migration pressure on cities are costs, and growth tends to raise pollution rather than stabilise it.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:8fa3a422', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q13", "question": "During 2018, a country experienced a rise in economic growth. Which of the following changes in the country may have had this effect?", "options": ["A decrease in the literacy rate", "A fall in the level of labour productivity", "An improvement in the quality of capital goods", "An increase in the rate of inflation"], "hint": "Which change would raise the economy''s ability to PRODUCE? Better machinery makes workers more productive.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — An improvement in the quality of capital goods</strong></p>\n<ul>\n<li>Better capital raises productivity and productive capacity, driving growth. Lower literacy and falling productivity would reduce growth; inflation is not a cause of growth.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:54214748', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q16", "question": "The table shows the growth rate of real GDP and nominal GDP in consecutive years in a country. What can be concluded from this table?", "options": ["Real GDP fell in Year 2", "There was no inflation in Year 1", "There was no inflation in Year 2", "There was no real output growth in Year 1"], "caseStudy": "<table style=\"width:100%;max-width:460px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\"></th><th style=\"padding:6px;\">Real GDP Growth (%)</th><th style=\"padding:6px;\">Nominal GDP Growth (%)</th></tr>\n<tr><td style=\"padding:6px;\">Year 1</td><td style=\"padding:6px;\">5</td><td style=\"padding:6px;\">5</td></tr>\n<tr><td style=\"padding:6px;\">Year 2</td><td style=\"padding:6px;\">4</td><td style=\"padding:6px;\">8</td></tr>\n</table>", "hint": "Nominal growth minus real growth ≈ inflation. In Year 1 they are equal — what does that tell you?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<p><strong>Answer: B — There was no inflation in Year 1</strong></p>\n<ul>\n<li>Nominal growth includes price rises; real growth strips them out. In Year 1 both are 5%, so prices did not rise — no inflation. In Year 2 the 4-point gap (8% vs 4%) shows inflation of about 4%. Real GDP still GREW 4% in Year 2, so it did not fall.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered ''A'', showing a misunderstanding of a falling rate of increase.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:9648cf33', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q17", "question": "The table shows how the size of a country''s real GDP has been changing over a four-year period. Which statement about the country MUST be true?", "options": ["Real GDP increased by more than money GDP between Year 1 and Year 4", "Real GDP increased by 10 percent between Year 2 and Year 3", "The greatest percentage increase in real GDP was between Year 1 and Year 2", "There was an increase in GDP per capita between Year 3 and Year 4"], "caseStudy": "<table style=\"width:100%;max-width:360px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Year</th><th style=\"padding:6px;\">Real GDP (£ millions)</th></tr>\n<tr><td style=\"padding:6px;\">1</td><td style=\"padding:6px;\">100</td></tr>\n<tr><td style=\"padding:6px;\">2</td><td style=\"padding:6px;\">110</td></tr>\n<tr><td style=\"padding:6px;\">3</td><td style=\"padding:6px;\">120</td></tr>\n<tr><td style=\"padding:6px;\">4</td><td style=\"padding:6px;\">125</td></tr>\n</table>", "hint": "Work out each PERCENTAGE increase, not the absolute rise. And note ''must be true'' — anything needing population data cannot be certain.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark · Quantitative skills</h5>\n<p><strong>Answer: C — The greatest percentage increase in real GDP was between Year 1 and Year 2</strong></p>\n<ul>\n<li>Year 1→2 = 10/100 = 10%; Year 2→3 = 10/110 = 9.1%; Year 3→4 = 5/120 = 4.2%. So the biggest % rise is Year 1→2 (B is wrong — that rise is 9.1%, not 10%). D cannot be known without population data.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:76891e28', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q19", "question": "The best way for a government to quickly increase economic growth is to", "options": ["boost private investment", "increase state spending on education", "raise corporation taxes", "sign a free trade agreement"], "hint": "The key word is QUICKLY. Education takes years to pay off and trade deals take years to negotiate. Raising taxes would slow growth.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — boost private investment</strong></p>\n<ul>\n<li>Investment raises demand and capacity relatively quickly. Education spending only raises growth over many years, trade agreements take years to negotiate, and higher corporation taxes would REDUCE growth.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:dc45b99e', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q20", "question": "Which of the following is normally part of a country''s GDP?", "options": ["Domestic services performed within a family", "Household savings", "Interest rates", "Investment spending by firms"], "hint": "GDP measures spending on newly produced output. Unpaid family work is not traded, savings are not spending, and an interest rate is a price — not output.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — Investment spending by firms</strong></p>\n<ul>\n<li>Investment is a component of GDP. Unpaid domestic work is not recorded, savings are income NOT spent, and interest rates are a price rather than a measure of output.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:e6d5135d', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q21", "question": "The diagram shows what has happened to a country''s real national output over a ten-year period. Which statement MUST be correct?", "options": ["Real national output was higher in Year 10 than in Year 0", "Real national output reached its highest in Year 5", "The price level was higher in Year 10 than in Year 0", "Unemployment was less in Year 10 than in Year 5"], "caseStudy": "<img src=\"/images/economics/3-1-real-national-output-diagram-extracted.png\" alt=\"Diagram from the OCR exam paper showing a country''s real national output on the vertical axis against time on the horizontal axis from Year 0 to Year 10: the line rises overall, peaks and dips slightly just after Year 5, then rises again to its highest point at Year 10\" style=\"display:block;width:100%;max-width:480px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "''MUST be correct'' — only read what the diagram actually shows. It plots REAL output against time; it says nothing about prices or unemployment.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: A — Real national output was higher in Year 10 than in Year 0</strong></p>\n<ul>\n<li>The line clearly ends higher than it began, so A must be true. Output peaks at Year 10, not Year 5. The diagram shows REAL output, so it tells us nothing about the price level, and nothing about unemployment.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:d24d95f6', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q23", "question": "Which of these is the best definition of economic growth?", "options": ["An increase in an economy''s employment level", "An increase in an economy''s population", "An increase in an economy''s productive capacity", "A reduction in an economy''s level of imports"], "hint": "Growth is about the economy''s ability to PRODUCE more. Employment and population are related but are not the definition.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — An increase in an economy''s productive capacity</strong></p>\n<ul>\n<li>Growth means the economy can produce more output. Rising employment or population may accompany growth but do not define it, and fewer imports is not growth.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:exam:5ce0c66a', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Which of the following is most likely to reduce economic growth?", "options": ["An increase in exports", "A stable price level", "High taxes on profits", "Low interest rates"], "hint": "Which option discourages firms from investing and expanding?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — High taxes on profits</strong></p>\n<ul>\n<li>High profit taxes leave firms less to reinvest and weaken the incentive to expand, reducing growth. Rising exports, stable prices and low interest rates all tend to SUPPORT growth.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-1-economic-growth:mcq:e33d0024', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "Economic growth is best defined as...", "options": ["A reduction in the level of imports", "An increase in an economy''s population", "An increase in an economy''s productive capacity", "An increase in the employment level"]}'::jsonb, '{"answer": 2, "explain": "Long-run economic growth is an increase in the economy''s potential productive capacity. Employment and population may accompany growth but do not define it."}'::jsonb),
('economics:3-1-economic-growth:mcq:cb2f317c', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "Which formula measures the rate of economic growth?", "options": ["New GDP − Previous GDP", "(Change in GDP ÷ Previous GDP) × 100", "Change in GDP ÷ Change in population", "(Total GDP ÷ Previous GDP) × 100"]}'::jsonb, '{"answer": 1, "explain": "Growth is a PERCENTAGE change: the change in GDP as a proportion of the previous GDP, × 100. ''New GDP − Previous GDP'' gives only the absolute change, not a rate."}'::jsonb),
('economics:3-1-economic-growth:mcq:749ba12a', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "GDP is £150 billion and the population is 5 million. GDP per capita is...", "options": ["£30,000", "£750,000", "£300,000", "£3,000"]}'::jsonb, '{"answer": 0, "explain": "GDP per capita = GDP ÷ population = £150bn ÷ 5m = £30,000."}'::jsonb)
